-- 2) Real airlines
ON DUPLICATE KEY UPDATE code_icao = VALUES(code_icao), name = VALUES(name), is_active = TRUE;


-- 3) Real airports, linked to destination rows above
ON DUPLICATE KEY UPDATE code_icao = VALUES(code_icao), name = VALUES(name), city_name = VALUES(city_name), country_code = VALUES(country_code), destination_id = VALUES(destination_id), latitude = VALUES(latitude), longitude = VALUES(longitude), timezone = VALUES(timezone), is_active = TRUE;


