    'VND' AS currency,
    cls.seat_total,
    CASE
        -- Một vài chuyến cố tình full để test nhãn "đầy chuyến"
        WHEN f.flight_no IN ('UI2801','UI2857','UI2863','UI2885') THEN 0
        -- Một vài chuyến gần hết ghế
        WHEN f.flight_no IN ('UI2803','UI2841','UI2875','UI2881') THEN LEAST(cls.seat_total, 3)
        ELSE cls.seat_available
    END AS seat_available,
    JSON_OBJECT(
        'checked_baggage_kg', cls.baggage_kg,
        'cabin_baggage_kg', 7,
        'note', 'Seed UI flight data'
    ) AS baggage_rule_json,
    JSON_OBJECT(
        'changeable', cls.changeable,
        'refundable', cls.refundable,
        'change_fee', cls.change_fee
