JOIN (
    SELECT 'economy' AS cabin_class, 'promo' AS fare_family, 1.00 AS price_multiplier,
           120 AS seat_total, 48 AS seat_available, 20 AS baggage_kg,
           TRUE AS changeable, FALSE AS refundable, 450000 AS change_fee
    UNION ALL
    SELECT 'economy', 'standard', 1.18,
           80, 26, 23,
           TRUE, TRUE, 300000
    UNION ALL
    SELECT 'business', 'business_flex', 2.80,
           16, 6, 32,
