-- ============================================================
-- V7_03B_UI_MORE_20_EACH_CITY_FLIGHTS.sql
-- Dữ liệu bổ sung cho UI vé máy bay.
-- Mục tiêu: mỗi tab trong ảnh có nhiều chuyến hơn.
-- Các tab được bổ sung:
--   Nội địa: Đà Nẵng, Hà Nội, TP HCM, Cần Thơ, Nha Trang, Phú Quốc
--   Quốc tế: Bangkok, Singapore, Seoul, Tokyo, Đài Bắc, Paris, London
-- Quy mô: mỗi tab có 20 chuyến bay đi tới điểm đó + 20 chuyến bay chiều về.
-- Tổng cộng: 13 tab x 40 chuyến = 520 chuyến bay.
-- Có thể dùng cho vé 1 chiều và ghép cặp khứ hồi.
-- Không dùng stored procedure, không dùng function sinh dữ liệu.
-- ============================================================

-- ============================================================
-- 1) DESTINATIONS CHO CÁC TAB BAY TRÊN UI
-- Dữ liệu điểm đến sân bay thật, dùng để airports.destination_id không bị NULL.
-- ============================================================
ON DUPLICATE KEY UPDATE name = VALUES(name), province = VALUES(province), region = VALUES(region), address = VALUES(address), latitude = VALUES(latitude), longitude = VALUES(longitude), is_active = TRUE, status = 'APPROVED', is_official = TRUE;

-- ============================================================
-- 2) AIRLINES
-- Hãng bay thật dùng cho dữ liệu chuyến bay mới.
-- ============================================================
ON DUPLICATE KEY UPDATE code_icao = VALUES(code_icao), name = VALUES(name), is_active = TRUE;

-- ============================================================
-- 3) AIRPORTS
-- Sân bay thật tương ứng với các tab UI.
-- ============================================================
ON DUPLICATE KEY UPDATE code_icao = VALUES(code_icao), name = VALUES(name), city_name = VALUES(city_name), country_code = VALUES(country_code), destination_id = VALUES(destination_id), latitude = VALUES(latitude), longitude = VALUES(longitude), timezone = VALUES(timezone), is_active = TRUE;

-- ============================================================
-- 4) CLEANUP DỮ LIỆU BỔ SUNG
-- Xóa đúng dải flight_no UI8xxx để chạy lại không bị trùng.
-- ============================================================
DELETE ffr FROM flight_fare_rules ffr JOIN flight_classes fc ON fc.id = ffr.flight_class_id JOIN flights f ON f.id = fc.flight_id WHERE f.flight_no IN (
    'VN8001', 'VJ8002', 'QH8003', 'VN8004', 'VJ8005', 'QH8006', 'VN8007', 'VJ8008', 'QH8009', 'VN8010',
    'VJ8011', 'QH8012', 'VN8013', 'VJ8014', 'QH8015', 'VN8016', 'VJ8017', 'QH8018', 'VN8019', 'VJ8020',
