-- ============================================================
-- 5) FLIGHTS
-- Mỗi tab có 20 chuyến đi tới điểm đó và 20 chuyến bay chiều về.
-- Các chuyến đều sau ngày 19/06/2026.
-- ============================================================

-- ============================================================
-- 6) FLIGHT_CLASSES
-- Dữ liệu hạng vé để UI lấy giá From, số ghế còn lại và trạng thái đầy chuyến.
-- Quy tắc:
--   seat_available = 0 ở toàn bộ class => chuyến bay đầy.
--   economy/saver là giá thấp nhất để UI hiển thị From.
-- ============================================================
ON DUPLICATE KEY UPDATE base_price = VALUES(base_price), tax_amount = VALUES(tax_amount), currency = VALUES(currency), seat_total = VALUES(seat_total), seat_available = VALUES(seat_available), baggage_rule_json = VALUES(baggage_rule_json), change_refund_rule_json = VALUES(change_refund_rule_json), is_active = TRUE;

-- ============================================================
-- 7) FLIGHT_FARE_RULES
-- Quy tắc giá trẻ em/người lớn tuổi theo từng class.
-- ============================================================
